/* Blobio extension bundle. Generated from src/. */
(() => {
  // background.png
  var background_default = "data:image/png;base64,";

  // src/features/BackgroundFeature.js
  var DEFAULT_CLASS_NAME = "blobio-background-enabled";
  var DEFAULT_STYLE_ID = "blobio-background-style";
  var BackgroundFeature = class {
    constructor({
      document = globalThis.document,
      backgroundUrl,
      logger = console,
      className = DEFAULT_CLASS_NAME,
      styleId = DEFAULT_STYLE_ID
    } = {}) {
      this.document = document;
      this.backgroundUrl = backgroundUrl;
      this.logger = logger;
      this.className = className;
      this.styleId = styleId;
      this.started = false;
      this.styleNode = null;
      this.observer = null;
      this.readyHandler = null;
    }
    start() {
      if (this.started) {
        return true;
      }
      if (!this.document?.documentElement || !this.backgroundUrl) {
        this.logger.warn("[Blobio] Background feature could not start: document or background image is missing.");
        return false;
      }
      this.ensureStyle();
      this.applyClasses();
      this.watchForBody();
      this.started = true;
      return true;
    }
    destroy() {
      this.disconnectObserver();
      if (this.readyHandler) {
        this.document.removeEventListener?.("DOMContentLoaded", this.readyHandler);
        this.readyHandler = null;
      }
      const style = this.styleNode || this.document.getElementById?.(this.styleId);
      style?.remove();
      this.styleNode = null;
      this.document.documentElement?.classList.remove(this.className);
      this.document.body?.classList.remove(this.className);
      this.started = false;
    }
    ensureStyle() {
      const existingStyle = this.document.getElementById?.(this.styleId);
      if (existingStyle) {
        this.styleNode = existingStyle;
        return;
      }
      const style = this.document.createElement("style");
      style.id = this.styleId;
      style.textContent = this.buildCss();
      const parent = this.document.head || this.document.documentElement;
      parent.appendChild(style);
      this.styleNode = style;
    }
    buildCss() {
      return `
html.${this.className},
body.${this.className} {
  min-height: 100%;
  background-color: #050607 !important;
  background-image: url("${this.backgroundUrl}") !important;
  background-position: center center !important;
  background-repeat: no-repeat !important;
  background-size: cover !important;
  background-attachment: fixed !important;
}

html.${this.className} body {
  background-color: transparent !important;
}
`.trim();
    }
    applyClasses() {
      this.document.documentElement.classList.add(this.className);
      this.document.body?.classList.add(this.className);
    }
    watchForBody() {
      if (this.document.body) {
        return;
      }
      const MutationObserver = this.document.defaultView?.MutationObserver || globalThis.MutationObserver;
      if (MutationObserver) {
        this.observer = new MutationObserver(() => {
          if (!this.document.body) {
            return;
          }
          this.document.body.classList.add(this.className);
          this.disconnectObserver();
        });
        this.observer.observe(this.document.documentElement, { childList: true });
        return;
      }
      this.readyHandler = () => this.applyClasses();
      this.document.addEventListener?.("DOMContentLoaded", this.readyHandler, { once: true });
    }
    disconnectObserver() {
      this.observer?.disconnect();
      this.observer = null;
    }
  };

  // src/main.js
  var INSTANCE_KEY = "__blobioExtension";
  var BlobioExtension = class {
    constructor(windowRef = globalThis) {
      this.window = windowRef;
      this.features = [];
      this.started = false;
    }
    start() {
      if (this.started) {
        return true;
      }
      const document = this.window.document;
      if (!document?.documentElement) {
        this.window.console?.warn("[Blobio] Extension could not start: document is not ready.");
        return false;
      }
      this.features = [
        new BackgroundFeature({
          document,
          backgroundUrl: background_default,
          logger: this.window.console || console
        })
      ];
      for (const feature of this.features) {
        feature.start();
      }
      this.started = true;
      return true;
    }
    destroy() {
      for (let index = this.features.length - 1; index >= 0; index -= 1) {
        this.features[index].destroy();
      }
      this.features = [];
      this.started = false;
    }
  };
  function startBlobioExtension(windowRef = globalThis) {
    if (windowRef[INSTANCE_KEY]) {
      return windowRef[INSTANCE_KEY];
    }
    const extension = new BlobioExtension(windowRef);
    windowRef[INSTANCE_KEY] = extension;
    extension.start();
    return extension;
  }
  startBlobioExtension(globalThis);
})();
